+
+    /// Canonical 6-regime adversarial schedule.
+    fn canonical_adversarial_schedule() -> Vec<AdversarialRegime> {
+        vec![
+            AdversarialRegime {
+                name: "warm_uniform",
+                txn_count: 500,
+                abort_probability: 0.03,
