+            target_reg,
+            0,
+            P4::Blob(record.to_vec()),
+            0,
+        );
+    } else {
+        b.emit_op(
+            Opcode::MakeRecord,
+            source_regs,
+            column_count,
+            target_reg,
+            P4::Affinity(affinity.to_owned()),
